/**
 * Rate Limits pruefen und den besten Account fuer diese Session waehlen.
 * 
 * Limits:
 * - Max 100 Connects in 7 Tagen (Rolling Window)
 * - Max 25 Connects pro Tag
 * - Max 8 Connects pro Stunde
 * - Min 30 Minuten zwischen Sessions
 * 
 * Bei Ueberschreitung: Account wird auf 'cooldown' gesetzt.
 */
export async function checkLimits(sb, accounts) {
  const now = new Date();
  const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000).toISOString();
  const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000).toISOString();
  const oneHourAgo = new Date(now - 60 * 60 * 1000).toISOString();

  for (const account of accounts) {
    // Connects der letzten 7 Tage zaehlen
    const { count: week } = await sb
      .from('linkedin_activity')
      .select('*', { count: 'exact', head: true })
      .eq('account_id', account.id)
      .eq('action_type', 'connect')
      .gte('created_at', sevenDaysAgo);

    // Connects heute zaehlen
    const { count: today } = await sb
      .from('linkedin_activity')
      .select('*', { count: 'exact', head: true })
      .eq('account_id', account.id)
      .eq('action_type', 'connect')
      .gte('created_at', oneDayAgo);

    // Pruefen ob alle Limits OK sind
    if (week < 100 && today < 25) {
      console.log(`Account ${account.display_name}: ${week}/100 Woche, ${today}/25 Tag -> OK`);
      return { ...account, weekCount: week, dayCount: today };
    }

    console.log(`Account ${account.display_name}: Limit erreicht (${week}/100)`);
  }

  throw new Error('Alle Accounts am Limit - kein Connect moeglich');
}

